#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        char s[100005]; scanf("%s",s);
        int freq[26]={0};
        for(int i=0;i<N;i++) freq[s[i]-'a']++;
        int maxf=0; for(int i=0;i<26;i++) if(freq[i]>maxf) maxf=freq[i];
        int rest = N - maxf;
        if(rest >= (maxf-1)/2) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

