import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        s = next(it)
        freq = [0]*26
        for ch in s:
            freq[ord(ch)-97] += 1
        maxf = max(freq)
        rest = N - maxf
        if rest >= (maxf-1)//2:
            out_lines.append('YES')
        else:
            out_lines.append('NO')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

