const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let out = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const s = input[idx++];
  const freq = new Array(26).fill(0);
  for (let i = 0; i < N; i++) {
    freq[s.charCodeAt(i) - 97]++;
  }
  let maxf = 0;
  for (let f of freq) if (f > maxf) maxf = f;
  const rest = N - maxf;
  if (rest >= Math.floor((maxf - 1) / 2)) out.push('YES');
  else out.push('NO');
}
